refsection.programlisting:
image = imread(fullpath(getIPCVpath() + "/images/2lines.png"));
gray = rgb2gray(image);
edges = gray > 128;
[accumulator, rho, theta] = imhough(edges);
peaks = imhoughpeaks(accumulator, 2);
lines = imhoughlines(rho, theta, peaks, size(edges));
imshow(edges);
axesHandle = gca();
axesHandle.auto_clear = "off";
for k = 1:size(lines, 1)
    endpoints = [lines(k, 1) lines(k, 2); lines(k, 3) lines(k, 4)];
    plotPoints = rect2cart(size(edges), endpoints);
    plot(plotPoints(:, 1), plotPoints(:, 2), "r-");
end
disp(lines);
